/**
 * Fundatio Design Foundation: Header (`header`) element helpers.
 *
 * @remarks
 * The header element (`<header>`) represents introductory content for its nearest
 * ancestor sectioning root or sectioning content element. It commonly contains a
 * heading (`<h1>`-`<h6>`), branding, navigation aids, or other introductory UI.
 *
 * Best-practice guidance:
 * - Use `<header>` to group introductory content for a page or section.
 * - Prefer meaningful structure (headings, landmarks) over generic containers.
 * - Avoid using `<header>` purely for styling. Use CSS classes for styling and
 *   keep semantics intentional.
 * - A top-level `<header>` (scoped to `<body>` and not inside sectioning content)
 *   may be exposed as a landmark; nested headers typically are not.
 *
 * This module provides small, framework-agnostic helpers so consumers can:
 * - create header elements in vanilla JS/TS without templates
 * - apply consistent global attributes safely
 * - use a stable "enhancement" hook if Fundatio ever needs runtime behavior
 *
 * This module has no side effects and does not mutate the DOM unless you call
 * its functions.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/HTML/Element/header
 * @see https://html.spec.whatwg.org/multipage/sections.html#the-header-element
 *
 * @module
 * @category Elements
 */

import { createElement, type ElementOf, type GlobalAttrs } from '../../../ts/dom';

/**
 * Structured ARIA input supported by Fundatio element factories.
 *
 * @remarks
 * This is intentionally a small, typed subset that covers common cases and
 * prevents typo-based ARIA bugs (e.g. `lable`).
 *
 * It is mapped into {@link GlobalAttrs.aria} for application by `dom.ts`.
 *
 * @category Attributes
 */
export type StructuredAria = {
  /**
   * Accessible label, mapped to `aria-label`.
   */
  label?: string;

  /**
   * ID reference to the labelling element(s), mapped to `aria-labelledby`.
   */
  labelledby?: string;

  /**
   * Decorative/hidden hint, mapped to `aria-hidden`.
   */
  hidden?: boolean;
};

/**
 * The semantic tag name for header elements.
 *
 * @category Constants
 */
export const HEADER_TAG = 'header' as const;

/**
 * A CSS selector targeting header elements.
 *
 * @category Constants
 */
export const HEADER_SELECTOR = 'header';

/**
 * Attribute bag for header creation/enhancement.
 *
 * @remarks
 * `<header>` accepts standard HTML global attributes.
 *
 * Fundatio also supports a structured ARIA input for common ARIA fields, which is
 * mapped into {@link GlobalAttrs.aria} without changing Fundatio's core DOM helpers.
 *
 * @category Attributes
 */
export type HeaderAttrs = Omit<GlobalAttrs, 'aria'> & {
  /**
   * Structured ARIA fields mapped into `aria-*` attributes.
   */
  aria?: StructuredAria;
};

/**
 * Normalize {@link HeaderAttrs} into {@link GlobalAttrs} for `dom.ts`.
 *
 * @param attrs - The header attributes.
 * @returns A {@link GlobalAttrs} object, or `undefined` if no attrs were provided.
 *
 * @category Internal
 */
function toGlobalAttrs(attrs?: HeaderAttrs): GlobalAttrs | undefined {
  if (!attrs) return undefined;

  const { aria, ...rest } = attrs;

  if (!aria) return rest;

  const mappedAria: NonNullable<GlobalAttrs['aria']> = {};

  if (typeof aria.label === 'string') mappedAria.label = aria.label;
  if (typeof aria.labelledby === 'string') mappedAria.labelledby = aria.labelledby;
  if (typeof aria.hidden === 'boolean') mappedAria.hidden = aria.hidden;

  // Only attach `aria` if something was actually defined.
  const hasMapped = Object.keys(mappedAria).length > 0;

  return hasMapped ? { ...rest, aria: mappedAria } : rest;
}

/**
 * Create a header element with optional text content and global attributes.
 *
 * @remarks
 * - Text content is assigned via `textContent` (never `innerHTML`).
 * - Global attributes are applied via Fundatio's shared DOM helper,
 *   including security guards that block inline event handler attributes
 *   (e.g. `onclick`) and raw `style` attribute strings.
 *
 * @param text - Optional text content for the header.
 * @param attrs - Optional attributes to apply.
 * @returns The created `<header>` element.
 *
 * @example
 * Create and append a header:
 * ```ts
 * import { createHeader } from "@Vastare/Fundatio/elements/layout/header";
 *
 * document.body.prepend(
 *   createHeader(undefined, { className: "site-header" })
 * );
 * ```
 *
 * @category DOM
 */
export function createHeader(text?: string, attrs?: HeaderAttrs): ElementOf<typeof HEADER_TAG> {
  return createElement(HEADER_TAG, toGlobalAttrs(attrs), text);
}

/**
 * Enhance header elements within a given root.
 *
 * @remarks
 * This is intentionally a no-op in `1.0.0`.
 *
 * Why does it exist?
 * - It establishes a stable integration pattern for frameworks (Vue/React/etc.)
 * - It allows future progressive enhancements without changing consumer code
 *
 * What it will never do:
 * - It will not inject styles (CSS remains the source of truth)
 * - It will not introduce framework-specific behavior
 *
 * @param root - The node to search within. Defaults to `document`.
 *
 * @category Enhancement
 */
export function enhanceHeaders(root: ParentNode = document): void {
  // v1.0.0: no runtime behavior for header.
  void root;
}
